  ShieldCheck,
  Clock,
  Sparkles,
  Wrench,
  ArrowUpRight,
} from "lucide-react";
import { WHY_US, ABOUT_IMAGE } from "../../mock";
import img9 from "../../assets/About_image2.png";

const ICONS = [ShieldCheck, Clock, Sparkles, Wrench];

